class GeneralLeadsController extends Controller
{
    public function index()
    {
        $cities  = City::latest()->get();
        $themes = Theme::where('user_id',43)->where(function($query) {
                    $query->where('theme_type','birthday')
                            ->orWhere('theme_type','marriage');
                })->get();
        $states = State::where(function($query) { 
                })->get();       
                
        $userdetail = User::select('id','name','email','mobile','username','business_name','toss_actual_pass','city','android_token','iphone_token')
		                                            ->where('role_id',"=",4)
		                                            ->where('is_active',1) 
		                                            ->orderBy('name','Asc')
		                                           ->get();
		 $pawteam1 = User::where('new_paw_team',1)->where('buy_lead_page_access',0)->get();

         
        $pawteam  = User::select('id','name','role_id','is_active','is_paw_team') 
        ->where('users.role_id',"!=",4)
        ->where('users.is_active',1) 
        ->where('users.is_paw_team',1) 
        ->where('users.new_paw_team',1) 
        ->orderBy('users.name','Asc')
        ->get();

		 
        return view('admin.general_leads',compact(['cities','themes','states','userdetail','pawteam']));
    }

