            general_leads.lead_type,'<br>','Lead Price : ',general_leads.price)  like ?";
            $query->whereRaw($sql, ["%{$keyword}%"]);
        })
        ->filterColumn('epdetails', function($query, $keyword) {
            $sql = "CONCAT(users.name,'<br>','Email : ',users.email,'<br>','Mobile : ',users.mobile,'<br>','City : ',users.city)  like ?";
            $query->whereRaw($sql, ["%{$keyword}%"]);
        })
         ->filterColumn('epfollowups', function($query, $keyword) {
            $sql = "CONCAT(users.name,'<br>','Email : ',users.email,'<br>','Mobile : ',users.mobile,'<br>','City : ',users.city)  like ?";
            $query->whereRaw($sql, ["%{$keyword}%"]);
        })
        ->filterColumn('purchased', function($query, $keyword) {
            
            if(strpos($keyword, 'not') !== false || strpos($keyword, 'Not') !== false) 
            {
                $query->whereNull('general_leads_buy.user_id');
            }
            else
            {
                $query->whereNotNull('general_leads_buy.user_id');
            }
        })
        ->make(true);
    }
    
    
    public function getdata1pooja(Request $request)
    {
        $cityname = $request->input('cityname');
         
         $start_date = $request->input('start_date');
        
        $end_date = $request->input('end_date');
        
        $teamid = $request->input('teamid');
         
         
         $selectteamid = $request->input('selectteamid');
         
        
        $leads = GeneralLead::select([
            'general_leads.*','general_leads_buy.user_id','general_leads_buy.id as generallead_id','general_leads_buy.created_at as lead_purchase_date','general_leads_buy.status as lead_status','general_leads_buy.purchase_type','general_leads.address as address','general_leads.event_category','general_leads_remarks.status as grstatus','general_leads_remarks.followup as grafollowup','general_leads_remarks.remarks as graremarks',
              DB::raw("CONCAT(users.name,'<br>','Email : ',IFNULL( users.email , 'NA' ),'<br>','Mobile : ',users.mobile,'<br>','City : ',users.city,'<br>','Event Planner Name : ',users.name,'<br>','<br>','<b>','Event Planner Id : ',users.id,'</b>','<br>',
              '<b>','Lead Purchased Category : ',purchase_type,'</b>',
              
              '<br>','Managed by : ',IFNULL( general_leads_remarks.managed_by , 'Not Assigned to Team Member' )) as epdetails"),
            DB::raw("CONCAT('Status : ',IFNULL( general_leads_remarks.status , 'NA' ),'<br>','Follow Up Date : ',IFNULL( general_leads_remarks.followup , 'NA' ),'<br>','Remarks : ',IFNULL( general_leads_remarks.remarks , 'NA' )) as epfollowups"),
            DB::raw("CONCAT('Lead Category : ',general_leads.package_type,
            '<br>',(CASE WHEN (general_leads.event_category = 'In Person Meeting' || general_leads.event_category = 'Office Location'|| general_leads.event_category = 'Client Place') THEN 'Meeting Time :' ELSE 'Lead Time :' END),general_leads.lead_time,'<br>','Lead Expiry : ',general_leads.expiry_date,'<br>','<b>','City : ','</b>',(CASE WHEN (general_leads.state_name IS NOT NULL) THEN general_leads.city ELSE general_leads.city END),'<br>','<b>','State : ','</b>',(CASE WHEN (general_leads.state_name IS NOT NULL) THEN general_leads.state_name ELSE ' Not mentioned ' END),'<br>','<b>','<b>','Location : ','</b>',general_leads.event_location,'<br>',
            (CASE WHEN (general_leads.event_category = 'In Person Meeting' || general_leads.event_category = 'Office Location'|| general_leads.event_category = 'Client Place') THEN 'Address : ' ELSE '' END),
            (CASE WHEN (general_leads.event_category = 'In Person Meeting' || general_leads.event_category = 'Office Location' || general_leads.event_category = 'Client Place') THEN general_leads.address ELSE '' END),
            (CASE WHEN (general_leads.event_category = 'In Person Meeting'|| general_leads.event_category = 'Office Location' || general_leads.event_category = 'Client Place') THEN '<br />' ELSE '' END),
            'Lead Id : ',general_leads.id) as leadsdetails"),
            //DB::raw("STR_TO_DATE(`quotations.event_date`, '%d-%m-%Y')  as eventdate"),
        ])
        
        //->where('general_leads.event_category','!=' , 'In Person Meeting')
        ->leftJoin("general_leads_buy","general_leads_buy.general_leads_id","=","general_leads.id")
        ->leftJoin("general_leads_remarks","general_leads_remarks.general_leads_buy_id","=","general_leads_buy.id")
        ->leftJoin("users","users.id","=","general_leads_buy.user_id")
        ->where('general_leads.event_category','<>' , 'Office Location')
        ->where('general_leads.event_category','<>' , 'Connect over call')
        ->where('general_leads.event_category','<>' , 'Virtual Meeting')
        ->where('general_leads.event_category','<>' , 'In Person Meeting')
        ->where('general_leads.event_category','<>' , 'Client Place')
        ->where('general_leads.event_category','<>' , 'Office Location,Client Place')
        ->where(function($leads) {
                    $leads->where(function($query) {
                            $query->where('general_leads.event_category', 'not like','%'. 'Office Location'.'%');
                        }) 
                        
                      ->orWhere(function($query) {
                            $query->where('general_leads.event_category', 'not like','%'. 'Connect over call'.'%');
                        })
                        
                        
                     ->orWhere(function($query) {
                            $query->where('general_leads.event_category', 'not like', '%'.'Virtual Meeting'.'%');
                        })   
                        
                    ->orWhere(function($query) {
                            $query->where('general_leads.event_category', 'not like', '%'.'In Person Meeting'.'%');
                        })  
                        
                        
                    ->orWhere(function($query) {
                            $query->where('general_leads.event_category', 'not like', '%'.'Client Place'.'%');
                        })  
                        
                    ; 
                 }) 
                 
         
        ;
        
        if(!empty($cityname))
        {
            $leads = $leads->where('general_leads.city','like', "%$cityname%");
        }

        if(!empty($start_date)&&!empty($end_date)&&($teamid !="0"))
        { 
