                    <option value="category2">Category2</option>
                </select>
                
                <button type="submit" class="btn btn-success btn-sm add_confirm_details" name="add_confirm_details" id="addconfirmdetails'.$leads->id.'" onclick="event.preventDefault();setvalue(\''.$leads->id.'\');" style="width:100%;">Send Sms</button>
