    public function removedata(Request $request)
    {
        $leadposted = explode("-", $request->id);
        $leadtype = $leadposted['0'];
        $id = $leadposted['1'];
        
        if($leadtype == 'genleadbuy')
        {
            $gen_lead = GeneralLeadBuy::find($id);
            
            if(Notification::where('lead_id',$gen_lead->general_leads_id)->where('lead_type','general_leads')->where('user_id',$gen_lead->user_id)->count() > 0)
            {
                $notifications = Notification::where('lead_id',$gen_lead->general_leads_id)->where('lead_type','general_leads')->where('user_id',$gen_lead->user_id)->get();
                
                foreach($notifications as $notification)
                {
                    $notification->delete();
                }
            }
            
            if($gen_lead->delete())
            {
                echo 'Data Deleted';
            }
            else
            {
                echo 'Error In Data Deletion';
            }
        }
        else if($leadtype == 'genlead')
        {
            $lead = GeneralLead::find($id);
        
            if(Notification::where('lead_id',$lead->id)->where('lead_type','general_leads')->count() > 0)
            {
                $notifications = Notification::where('lead_id',$lead->id)->where('lead_type','general_leads')->get();
                
                foreach($notifications as $notification)
                {
                    $notification->delete();
                }
            }
            
            if($lead->delete())
            {
                echo 'Data Deleted';
            }
            else
            {
                echo 'Error In Data Deletion';
            }
        }
    }

