      public function setmuteconnect($id,$value)
    {
        $resultString = [];
        $data = GeneralLead::findOrFail($id);

        $cusid = $data->custom_lead_id;
        
        
        $event_category = $data->event_category;
        
        //dd($cusid);
        if($data)
        {
            $data->mute = $value;
        }
        
        
        if($data->save())
        {
            
             $resultString['lastquoteid'] = 'updated  $value';
             echo(json_encode($resultString));
                    
             
        }
        else
        {
            $resultString['lastquoteid'] = '';
            echo(json_encode($resultString));
        }
    }
    
    
