     public function sethoneymoonassign($id,$value,$assigned_name,$assigned_id)
    {
        $resultString = [];
        $data = GeneralLead::findOrFail($id);
        
        $today = date('d/m/Y h:i:s');
         
            
        $data->honeymoon_sent = $value; 
        
        $data->honeymoon_sent_added_by = $assigned_name; 
          
        $data->honeymoon_sent_added_on = $today; 
         
        if($data->save())
        { 
            if($value == "Yes")
                {
                $honeymoonform = new HoneymoonForm();
                        
                        $honeymoonform->name = $data->name;
                        $honeymoonform->email = $data->email;
                        $honeymoonform->mobile = $data->mobile;
                        
                        $honeymoonform->city = $data->city;
                        $honeymoonform->detail_from = "lead Page";
                        
                        $curdate = date("d-m-Y");
                        
                        $honeymoonform->generallds_id = $data->id;
                        
                        if($honeymoonform->save())
                        {
                             $resultString['lastquoteid'] = 'updated to $value';
                            echo(json_encode($resultString));
                        }
                        else
                        {
                            $resultString['lastquoteid'] = 'Unable to add in Honeymoon';
                            echo(json_encode($resultString));
                        }
            }
            
           if($value == "No")
                {
               $honeymoonform = HoneymoonForm::where('generallds_id',$data->id)->latest()->first();
               if(!empty($honeymoonform))
               {
                    if($honeymoonform->delete())
                    {
                        $resultString['lastquoteid'] = 'Data Deleted';
                            echo(json_encode($resultString));
                    }
                    else
                    {
                        $resultString['lastquoteid'] = 'Not able to delete';
                            echo(json_encode($resultString));
                    }
               }
           }
        }
        else
        {
            $resultString['lastquoteid'] = '';
            echo(json_encode($resultString));
        }
    }  
    
    
