    public function exportsold($startdate,$enddate,$purchasetype) 
    {

        $startdate = $startdate;
            
        $enddate = $enddate;

        $purchasetype = $purchasetype;
         
        $today = date('d-m-Y-h:i:s');
          
         return Excel::download(new GeneralLeadsSold($startdate,$enddate,$purchasetype), $today."-".$purchasetype.'_sold_leads.xlsx');
    }
     
        
